const SK="inedisav_2026_v5",AK="inedisav_auth_v5",UK="inedisav_users_v5",DK="inedisav_data_v5";

function ls(k,fb){try{const r=localStorage.getItem(k);return r?JSON.parse(r):fb;}catch{return fb;}}
function ss(k,v){try{localStorage.setItem(k,JSON.stringify(v));}catch{}}
