// ══ LOGIN ══════════════════════════════════════════════════════════════
function Login({onLogin}){
  const [u,setU]=useState(""),[p,setP]=useState(""),[err,setErr]=useState(""),[show,setShow]=useState(false);
  function go(){
    const users=ls(UK,USUARIOS_INICIALES);
    const usr=users[u.trim().toLowerCase()];
    if(!usr||usr.password!==p){setErr("Usuario o contraseña incorrectos");return;}
    const sess={username:u.trim().toLowerCase(),role:usr.role,nombre:usr.nombre,grado:usr.grado};
    ss(AK,sess);onLogin(sess);
  }
  return(
    <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#0d47a1,#1565c0)",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{background:"#fff",borderRadius:16,padding:"40px 36px",width:340,boxShadow:"0 8px 32px rgba(0,0,0,.25)"}}>
        <div style={{textAlign:"center",marginBottom:28}}>
          <div style={{fontSize:36}}>🏫</div>
          <div style={{fontWeight:800,fontSize:18,color:"#1e3a5f",marginTop:8}}>INEDISAV</div>
          <div style={{fontSize:12,color:"#6b7280",marginTop:2}}>IED Sarid Arteta de Vásquez · 2026</div>
        </div>
        <label style={{fontSize:12,fontWeight:600,color:"#374151",display:"block",marginBottom:4}}>Usuario</label>
        <input value={u} onChange={e=>setU(e.target.value)} onKeyDown={e=>e.key==="Enter"&&go()} placeholder="ej: admin"
          style={{width:"100%",padding:"10px 12px",borderRadius:8,border:"1.5px solid #d1d5db",fontSize:14,boxSizing:"border-box",marginBottom:12}}/>
        <label style={{fontSize:12,fontWeight:600,color:"#374151",display:"block",marginBottom:4}}>Contraseña</label>
        <div style={{position:"relative",marginBottom:6}}>
          <input value={p} onChange={e=>setP(e.target.value)} type={show?"text":"password"} onKeyDown={e=>e.key==="Enter"&&go()} placeholder="••••••••"
            style={{width:"100%",padding:"10px 12px",borderRadius:8,border:"1.5px solid #d1d5db",fontSize:14,boxSizing:"border-box"}}/>
          <button onClick={()=>setShow(!show)} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",fontSize:16}}>{show?"🙈":"👁️"}</button>
        </div>
        {err&&<div style={{color:"#dc3545",fontSize:12,marginBottom:8,textAlign:"center"}}>{err}</div>}
        <button onClick={go} style={{width:"100%",padding:11,borderRadius:8,background:"#1565c0",color:"#fff",fontWeight:700,fontSize:15,border:"none",cursor:"pointer",marginTop:8}}>Ingresar</button>
        <div style={{marginTop:14,fontSize:11,color:"#9ca3af",textAlign:"center"}}>Admin: <b>admin</b> / <b>admin2026</b></div>
      </div>
    </div>
  );
}

// ══ ADMIN PANEL ════════════════════════════════════════════════════════
function AdminPanel({onClose,datosEscuela,onDataUpdate}){
  const [subTab,setSubTab]=useState("usuarios");
  const [usuarios,setUsuarios]=useState(()=>ls(UK,USUARIOS_INICIALES));
  const [editUser,setEditUser]=useState(null);
  const [newPass,setNewPass]=useState("");
  const [msg,setMsg]=useState("");
  const [simatMsg,setSimatMsg]=useState("");
  const [confirmarBorrar,setConfirmarBorrar]=useState(false);
  // Nuevo estudiante
  const grados=GRADOS_ORDEN.filter(g=>datosEscuela[g]);
  const [ne,setNe]=useState({nombre:"",genero:"M",documento:"",perid:"",simatEst:"NO REGISTRADO",telefono:"",grado:grados[0]||"",ruta:"",transportador:"",fechaNac:""});
  const [neMsg,setNeMsg]=useState("");
  // Edit estudiante
  const [editIdx,setEditIdx]=useState(null);
  const [editData,setEditData]=useState({});
  const [editMsg,setEditMsg]=useState("");
  // Nuevo usuario
  const [showNU,setShowNU]=useState(false);
  const [nu,setNu]=useState({username:"",password:"",nombre:"",role:"docente",grado:""});
  const [nuMsg,setNuMsg]=useState("");
  // Tipos
  const [tiposFilas,setTiposFilas]=useState(()=>GRADOS_ORDEN.filter(g=>datosEscuela[g]).map(g=>({grado:g,tutor:datosEscuela[g]?.tutor||""})));
  const [tiposMsg,setTiposMsg]=useState("");

  function guardarPass(username){
    if(!newPass.trim())return;
    const upd={...usuarios,[username]:{...usuarios[username],password:newPass.trim()}};
    setUsuarios(upd);ss(UK,upd);setEditUser(null);setNewPass("");setMsg("✅ Contraseña actualizada");setTimeout(()=>setMsg(""),2000);
  }
  function borrarBD(){localStorage.clear();ss(DK,DATOS_INICIAL);ss(UK,USUARIOS_INICIALES);window.location.reload();}
  function handleSIMAT(e){
    const file=e.target.files[0];if(!file)return;setSimatMsg("Procesando...");
    const reader=new FileReader();
    reader.onload=(ev)=>{
      try{
        const wb=XLSX.read(ev.target.result,{type:"array"});
        const simat=XLSX.utils.sheet_to_json(wb.Sheets["SIMAT"]||wb.Sheets[wb.SheetNames[0]]);
        const tipos=XLSX.utils.sheet_to_json(wb.Sheets["Tipos"]||wb.Sheets[wb.SheetNames[1]],{header:1});
        const tm={};tipos.forEach(r=>{if(r[17]&&r[18])tm[String(r[17]).trim()]=String(r[18]).trim();});
        const nd={};
        simat.forEach(r=>{
          const grado=(r["GRADO"]||r["Grado"]||"").toString().trim();if(!grado)return;
          if(!nd[grado])nd[grado]={tutor:tm[grado]||"",estudiantes:[]};
          const nombre=(r["APELLIDOS_Y_NOMBRES"]||"").toString().trim();if(!nombre)return;
          let tel="";try{const t=parseInt(String(r["TELEFONO"]||"").replace(/[^0-9]/g,""));if(t>0)tel=String(t);}catch{}
          nd[grado].estudiantes.push({
            nombre,
            genero:(r["GENERO"]||"").toString().trim().toUpperCase(),
            estado:(r["COMISION FINAL"]||"MATRICULADO").toString().trim().toUpperCase()||"MATRICULADO",
            documento:(r["DOCUMENTO"]||"").toString().trim(),
            perid:(r["PERID"]||"").toString().trim(),
            simat:(r["SIMAT"]||"NO REGISTRADO").toString().trim().toUpperCase()||"NO REGISTRADO",
            telefono:tel,
            ruta:(r["RUTA"]||"").toString().trim(),
            transportador:(r["TRANSPORTADOR"]||"").toString().trim(),
            fechaNac:(r["FECHA_NACIMIENTO"]||r["FECHA NACIMIENTO"]||"").toString().trim(),
          });
        });
        ss(DK,nd);onDataUpdate(nd);
        setSimatMsg("✅ Cargado: "+Object.keys(nd).length+" grados, "+simat.length+" estudiantes");
      }catch(err){setSimatMsg("❌ Error: "+err.message);}
    };
    reader.readAsArrayBuffer(file);
  }
  function agregarEst(){
    if(!ne.nombre.trim()){setNeMsg("⚠️ Nombre obligatorio");return;}
    const upd=JSON.parse(JSON.stringify(datosEscuela));
    upd[ne.grado].estudiantes.push({
      nombre:ne.nombre.trim().toUpperCase(),genero:ne.genero,documento:ne.documento.trim(),
      perid:ne.perid.trim(),simat:ne.simatEst,estado:"MATRICULADO",telefono:ne.telefono.trim(),
      ruta:ne.ruta.trim(),transportador:ne.transportador.trim(),fechaNac:ne.fechaNac
    });
    ss(DK,upd);onDataUpdate(upd);
    setNeMsg("✅ Agregado a "+ne.grado);setNe({...ne,nombre:"",documento:"",perid:"",telefono:"",ruta:"",transportador:"",fechaNac:""});
    setTimeout(()=>setNeMsg(""),3000);
  }
  function startEdit(grado,i){setEditIdx({grado,i});setEditData({...datosEscuela[grado].estudiantes[i]});}
  function cancelEdit(){setEditIdx(null);setEditData({});}
  function saveEdit(){
    if(!editData.nombre?.trim()){setEditMsg("⚠️ Nombre obligatorio");return;}
    const upd=JSON.parse(JSON.stringify(datosEscuela));
    upd[editIdx.grado].estudiantes[editIdx.i]={...editData,nombre:editData.nombre.trim().toUpperCase()};
    ss(DK,upd);onDataUpdate(upd);setEditIdx(null);setEditData({});
    setEditMsg("✅ Actualizado");setTimeout(()=>setEditMsg(""),2500);
  }
  function deleteEst(grado,i){
    if(!window.confirm("¿Eliminar este estudiante?"))return;
    const upd=JSON.parse(JSON.stringify(datosEscuela));
    upd[grado].estudiantes.splice(i,1);
    ss(DK,upd);onDataUpdate(upd);
    // Reindex appState
    const cur=ls(SK,{});const gs=cur[grado]||{};
    ["comisiones","asistencia","notas","entregas","simat"].forEach(sec=>{
      if(!gs[sec])return;const ri={};
      Object.entries(gs[sec]).forEach(([idx,val])=>{const n=parseInt(idx);if(n<i)ri[n]=val;else if(n>i)ri[n-1]=val;});
      gs[sec]=ri;
    });
    cur[grado]=gs;ss(SK,cur);
    setEditMsg("✅ Eliminado");setTimeout(()=>setEditMsg(""),2500);
  }
  function crearUsuario(){
    if(!nu.username.trim()||!nu.password.trim()||!nu.nombre.trim()){setNuMsg("⚠️ Completa todos los campos");return;}
    if(nu.role==="docente"&&!nu.grado){setNuMsg("⚠️ Selecciona un grado");return;}
    const key=nu.username.trim().toLowerCase().replace(/\s/g,"");
    if(usuarios[key]){setNuMsg("⚠️ Usuario ya existe");return;}
    const upd={...usuarios,[key]:{password:nu.password.trim(),role:nu.role,nombre:nu.nombre.trim().toUpperCase(),grado:nu.role==="docente"?nu.grado:null}};
    setUsuarios(upd);ss(UK,upd);
    setNuMsg("✅ Usuario "+key+" creado");setNu({username:"",password:"",nombre:"",role:"docente",grado:""});setShowNU(false);
    setTimeout(()=>setNuMsg(""),3000);
  }
  function guardarTipos(){
    if(tiposFilas.some(f=>!f.grado.trim())){setTiposMsg("⚠️ Hay filas sin nombre de grado");return;}
    const upd=JSON.parse(JSON.stringify(datosEscuela));
    tiposFilas.forEach(f=>{const g=f.grado.trim();if(!upd[g])upd[g]={tutor:f.tutor.trim(),estudiantes:[]};else upd[g].tutor=f.tutor.trim();});
    ss(DK,upd);onDataUpdate(upd);setTiposMsg("✅ Guardado");setTimeout(()=>setTiposMsg(""),3000);
  }

  const TABS=[["usuarios","👥 Usuarios"],["estudiantes","➕ Estudiantes"],["tipos","🏫 Grados/Tutores"],["simat","📂 Importar SIMAT"],["borrar","🗑️ Borrar BD"]];
  const CAMPO=(label,val,onChange,type="text",placeholder="")=>(
    <div>
      <label style={{fontSize:11,fontWeight:600,color:"#374151",display:"block",marginBottom:3}}>{label}</label>
      <input type={type} value={val} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
        style={{width:"100%",padding:"7px 10px",borderRadius:7,border:"1.5px solid #d1d5db",fontSize:12,boxSizing:"border-box"}}/>
    </div>
  );

  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{background:"#fff",borderRadius:16,width:"min(960px,99vw)",maxHeight:"92vh",display:"flex",flexDirection:"column",boxShadow:"0 8px 40px rgba(0,0,0,.3)"}}>
        <div style={{background:"#1565c0",color:"#fff",padding:"14px 20px",borderRadius:"16px 16px 0 0",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <span style={{fontWeight:700,fontSize:15}}>⚙️ Panel de Administración</span>
          <button onClick={onClose} style={{background:"none",border:"none",color:"#fff",fontSize:20,cursor:"pointer"}}>✕</button>
        </div>
        <div style={{display:"flex",borderBottom:"2px solid #e3e8f0",padding:"0 8px",overflowX:"auto",gap:2}}>
          {TABS.map(([k,l])=>(
            <button key={k} onClick={()=>setSubTab(k)}
              style={{padding:"8px 10px",border:"none",background:"none",cursor:"pointer",fontWeight:subTab===k?700:400,whiteSpace:"nowrap",
                color:subTab===k?"#1565c0":"#6b7280",borderBottom:subTab===k?"3px solid #1565c0":"3px solid transparent",marginBottom:-2,fontSize:11}}>
              {l}
            </button>
          ))}
        </div>
        <div style={{padding:20,overflowY:"auto",flex:1}}>
          {msg&&<div style={{background:"#d4edda",color:"#1e7e34",padding:"8px 12px",borderRadius:8,marginBottom:12,fontSize:13}}>{msg}</div>}

          {/* ── USUARIOS ── */}
          {subTab==="usuarios"&&(
            <div>
              {nuMsg&&<div style={{background:nuMsg.startsWith("✅")?"#d4edda":"#fff3cd",color:nuMsg.startsWith("✅")?"#1e7e34":"#856404",padding:"7px 12px",borderRadius:7,marginBottom:10,fontSize:12,fontWeight:600}}>{nuMsg}</div>}
              <button onClick={()=>setShowNU(!showNU)} style={{padding:"8px 18px",borderRadius:8,background:"#1565c0",color:"#fff",fontWeight:700,fontSize:13,border:"none",cursor:"pointer",marginBottom:12}}>
                ➕ Crear nuevo usuario
              </button>
              {showNU&&(
                <div style={{background:"#f0f4ff",border:"1.5px solid #1565c030",borderRadius:10,padding:16,marginBottom:16}}>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
                    {CAMPO("Usuario *",nu.username,v=>setNu({...nu,username:v.toLowerCase()}),"text","ej: maria.perez")}
                    {CAMPO("Contraseña *",nu.password,v=>setNu({...nu,password:v}),"text","ej: maria2026")}
                    <div style={{gridColumn:"1/-1"}}>{CAMPO("Nombre completo *",nu.nombre,v=>setNu({...nu,nombre:v}),"text","ej: MARIA PEREZ GOMEZ")}</div>
                    <div>
                      <label style={{fontSize:11,fontWeight:600,color:"#374151",display:"block",marginBottom:3}}>Rol *</label>
                      <select value={nu.role} onChange={e=>setNu({...nu,role:e.target.value,grado:""})}
                        style={{width:"100%",padding:"7px 10px",borderRadius:7,border:"1.5px solid #d1d5db",fontSize:12}}>
                        <option value="docente">👤 Docente</option>
                        <option value="coordinador">📋 Coordinador</option>
                        <option value="admin">👑 Administrador</option>
                      </select>
                    </div>
                    {nu.role==="docente"&&(
                      <div>
                        <label style={{fontSize:11,fontWeight:600,color:"#374151",display:"block",marginBottom:3}}>Grado *</label>
                        <select value={nu.grado} onChange={e=>setNu({...nu,grado:e.target.value})}
                          style={{width:"100%",padding:"7px 10px",borderRadius:7,border:"1.5px solid #d1d5db",fontSize:12}}>
                          <option value="">— Selecciona —</option>
                          {grados.map(g=><option key={g} value={g}>{g}</option>)}
                        </select>
                      </div>
                    )}
                  </div>
                  <button onClick={crearUsuario} style={{padding:"7px 20px",borderRadius:7,background:"#1e7e34",color:"#fff",fontWeight:700,fontSize:13,border:"none",cursor:"pointer"}}>✅ Guardar usuario</button>
                </div>
              )}
              {/* Lista todos los usuarios */}
              {Object.entries(usuarios).map(([username,u])=>{
                const icon=u.role==="admin"?"👑":u.role==="coordinador"?"📋":"👤";
                const rlabel=u.role==="admin"?"Admin":u.role==="coordinador"?"Coordinador":"Docente";
                const rbg=u.role==="admin"?"#e8edf5":u.role==="coordinador"?"#f3d9fa":"#fff";
                return(
                  <div key={username} style={{border:"1px solid #e9ecf0",borderRadius:8,padding:"9px 14px",marginBottom:6,display:"flex",alignItems:"center",gap:10,background:rbg}}>
                    <span style={{fontSize:16}}>{icon}</span>
                    <div style={{flex:1}}>
                      <span style={{fontWeight:600,fontSize:13}}>{username}</span>
                      <span style={{fontSize:10,color:"#6b7280",marginLeft:6}}>({rlabel})</span>
                      <div style={{fontSize:11,color:"#6b7280"}}>{u.nombre}{u.grado?" · "+u.grado:""}</div>
                    </div>
                    {editUser===username?(
                      <div style={{display:"flex",gap:6}}>
                        <input value={newPass} onChange={e=>setNewPass(e.target.value)} placeholder="Nueva clave"
                          style={{padding:"5px 8px",borderRadius:6,border:"1.5px solid #ddd",fontSize:12,width:120}}/>
                        <button onClick={()=>guardarPass(username)} style={{padding:"5px 10px",borderRadius:6,background:"#1565c0",color:"#fff",border:"none",cursor:"pointer",fontSize:12}}>Guardar</button>
                        <button onClick={()=>setEditUser(null)} style={{padding:"5px 10px",borderRadius:6,background:"#e9ecef",border:"none",cursor:"pointer",fontSize:12}}>✕</button>
                      </div>
                    ):(
                      <button onClick={()=>{setEditUser(username);setNewPass("");}} style={{padding:"5px 12px",borderRadius:6,background:"#e9ecef",border:"none",cursor:"pointer",fontSize:12}}>🔑 Cambiar clave</button>
                    )}
                  </div>
                );
              })}
            </div>
          )}

          {/* ── NUEVO/EDITAR ESTUDIANTE ── */}
          {subTab==="estudiantes"&&(
            <div>
              {/* Selector de grado */}
              <div style={{marginBottom:14}}>
                <label style={{fontSize:12,fontWeight:600,color:"#374151",display:"block",marginBottom:4}}>Grado a gestionar</label>
                <select value={ne.grado} onChange={e=>setNe({...ne,grado:e.target.value})}
                  style={{padding:"8px 14px",borderRadius:8,border:"1.5px solid #ddd",fontSize:13,width:"100%"}}>
                  {grados.map(g=><option key={g} value={g}>{g} — {datosEscuela[g]?.tutor||""}</option>)}
                </select>
              </div>
              {/* Formulario agregar */}
              <div style={{background:"#f0f4ff",border:"1.5px solid #1565c030",borderRadius:10,padding:14,marginBottom:14}}>
                <div style={{fontWeight:700,fontSize:13,color:"#1e3a5f",marginBottom:10}}>➕ Agregar nuevo estudiante</div>
                {neMsg&&<div style={{background:neMsg.startsWith("✅")?"#d4edda":"#fff3cd",color:neMsg.startsWith("✅")?"#1e7e34":"#856404",padding:"6px 10px",borderRadius:7,marginBottom:8,fontSize:12,fontWeight:600}}>{neMsg}</div>}
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
                  <div style={{gridColumn:"1/-1"}}>{CAMPO("Apellidos y Nombres *",ne.nombre,v=>setNe({...ne,nombre:v}),"text","ej: GARCIA LOPEZ JUAN PABLO")}</div>
                  <div>
                    <label style={{fontSize:11,fontWeight:600,color:"#374151",display:"block",marginBottom:3}}>Género</label>
                    <select value={ne.genero} onChange={e=>setNe({...ne,genero:e.target.value})}
                      style={{width:"100%",padding:"7px 10px",borderRadius:7,border:"1.5px solid #d1d5db",fontSize:12}}>
                      <option value="M">Masculino (M)</option><option value="F">Femenino (F)</option>
                    </select>
                  </div>
                  {CAMPO("Fecha Nacimiento",ne.fechaNac,v=>setNe({...ne,fechaNac:v}),"date")}
                  {CAMPO("Documento",ne.documento,v=>setNe({...ne,documento:v}),"text","ej: 1234567890")}
                  {CAMPO("PERID",ne.perid,v=>setNe({...ne,perid:v}),"text","ej: 654321")}
                  {CAMPO("Teléfono",ne.telefono,v=>setNe({...ne,telefono:v}),"text","ej: 3001234567")}
                  <div>
                    <label style={{fontSize:11,fontWeight:600,color:"#374151",display:"block",marginBottom:3}}>Estado SIMAT</label>
                    <select value={ne.simatEst} onChange={e=>setNe({...ne,simatEst:e.target.value})}
                      style={{width:"100%",padding:"7px 10px",borderRadius:7,border:"1.5px solid #d1d5db",fontSize:12}}>
                      {SIMAT_ESTADOS.map(s=><option key={s.key} value={s.key}>{s.label}</option>)}
                    </select>
                  </div>
                  {CAMPO("Ruta",ne.ruta,v=>setNe({...ne,ruta:v}),"text","ej: Ruta 3")}
                  {CAMPO("Transportador",ne.transportador,v=>setNe({...ne,transportador:v}),"text","ej: Transportes ABC")}
                </div>
                <button onClick={agregarEst} style={{padding:"8px 20px",borderRadius:8,background:"#1565c0",color:"#fff",fontWeight:700,fontSize:13,border:"none",cursor:"pointer"}}>➕ Agregar Estudiante</button>
              </div>
              {/* Lista editable */}
              {ne.grado&&datosEscuela[ne.grado]&&(
                <div>
                  <div style={{fontWeight:700,fontSize:12,color:"#1e3a5f",marginBottom:6}}>
                    Estudiantes en {ne.grado} ({datosEscuela[ne.grado].estudiantes.length})
                  </div>
                  {editMsg&&<div style={{background:editMsg.startsWith("✅")?"#d4edda":"#fff3cd",color:editMsg.startsWith("✅")?"#1e7e34":"#856404",padding:"6px 10px",borderRadius:7,marginBottom:8,fontSize:12,fontWeight:600}}>{editMsg}</div>}
                  <div style={{maxHeight:360,overflowY:"auto",border:"1px solid #e9ecf0",borderRadius:10}}>
                    {datosEscuela[ne.grado].estudiantes.map((est,i)=>(
                      <div key={i}>
                        {editIdx?.grado===ne.grado&&editIdx?.i===i?(
                          <div style={{background:"#f0f4ff",border:"2px solid #1565c040",padding:12,margin:4,borderRadius:8}}>
                            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
                              <div style={{gridColumn:"1/-1"}}>{CAMPO("Apellidos y Nombres",editData.nombre||"",v=>setEditData({...editData,nombre:v}))}</div>
                              <div>
                                <label style={{fontSize:11,fontWeight:600,color:"#374151",display:"block",marginBottom:3}}>Género</label>
                                <select value={editData.genero||"M"} onChange={e=>setEditData({...editData,genero:e.target.value})}
                                  style={{width:"100%",padding:"6px 9px",borderRadius:6,border:"1.5px solid #ddd",fontSize:12}}>
                                  <option value="M">M</option><option value="F">F</option>
                                </select>
                              </div>
                              {CAMPO("Fecha Nacimiento",editData.fechaNac||"",v=>setEditData({...editData,fechaNac:v}),"date")}
                              {CAMPO("Documento",editData.documento||"",v=>setEditData({...editData,documento:v}))}
                              {CAMPO("PERID",editData.perid||"",v=>setEditData({...editData,perid:v}))}
                              {CAMPO("Teléfono",editData.telefono||"",v=>setEditData({...editData,telefono:v}))}
                              <div>
                                <label style={{fontSize:11,fontWeight:600,color:"#374151",display:"block",marginBottom:3}}>Estado SIMAT</label>
                                <select value={editData.simat||"NO REGISTRADO"} onChange={e=>setEditData({...editData,simat:e.target.value})}
                                  style={{width:"100%",padding:"6px 9px",borderRadius:6,border:"1.5px solid #ddd",fontSize:12}}>
                                  {SIMAT_ESTADOS.map(s=><option key={s.key} value={s.key}>{s.label}</option>)}
                                </select>
                              </div>
                              {CAMPO("Ruta",editData.ruta||"",v=>setEditData({...editData,ruta:v}))}
                              {CAMPO("Transportador",editData.transportador||"",v=>setEditData({...editData,transportador:v}))}
                            </div>
                            <div style={{display:"flex",gap:8}}>
                              <button onClick={saveEdit} style={{padding:"6px 16px",borderRadius:6,background:"#1565c0",color:"#fff",fontWeight:700,fontSize:12,border:"none",cursor:"pointer"}}>💾 Guardar</button>
                              <button onClick={cancelEdit} style={{padding:"6px 14px",borderRadius:6,background:"#e9ecef",fontSize:12,border:"none",cursor:"pointer"}}>Cancelar</button>
                            </div>
                          </div>
                        ):(
                          <div style={{padding:"7px 12px",fontSize:12,borderBottom:"1px solid #f0f4f8",background:i%2===0?"#fff":"#f9fbff",display:"flex",gap:8,alignItems:"center"}}>
                            <span style={{color:"#9ca3af",minWidth:24}}>{i+1}</span>
                            <span style={{flex:1,fontWeight:500}}>{est.nombre}</span>
                            <span style={{color:"#6b7280"}}>{est.genero}</span>
                            {est.fechaNac&&<span style={{color:"#6b7280",fontSize:11}}>🎂{est.fechaNac}</span>}
                            {est.ruta&&<span style={{color:"#1565c0",fontSize:11}}>🚌{est.ruta}</span>}
                            <button onClick={()=>startEdit(ne.grado,i)} style={{padding:"3px 8px",borderRadius:5,background:"#e8edf5",border:"none",cursor:"pointer",fontSize:11,color:"#1565c0",fontWeight:600}}>✏️</button>
                            <button onClick={()=>deleteEst(ne.grado,i)} style={{padding:"3px 8px",borderRadius:5,background:"#f8d7da",border:"none",cursor:"pointer",fontSize:11,color:"#721c24",fontWeight:600}}>🗑️</button>
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* ── GRADOS Y TUTORES ── */}
          {subTab==="tipos"&&(
            <div>
              {tiposMsg&&<div style={{background:tiposMsg.startsWith("✅")?"#d4edda":"#fff3cd",color:tiposMsg.startsWith("✅")?"#1e7e34":"#856404",padding:"7px 12px",borderRadius:7,marginBottom:10,fontSize:12,fontWeight:600}}>{tiposMsg}</div>}
              <div style={{border:"1px solid #e9ecf0",borderRadius:10,overflow:"hidden",marginBottom:12}}>
                <div style={{background:"#1565c0",color:"#fff",padding:"8px 14px",display:"grid",gridTemplateColumns:"40px 1fr 1fr 40px",gap:8,fontSize:12,fontWeight:700}}>
                  <span>#</span><span>Grado</span><span>Director(a)</span><span></span>
                </div>
                <div style={{maxHeight:380,overflowY:"auto"}}>
                  {tiposFilas.map((f,i)=>(
                    <div key={i} style={{display:"grid",gridTemplateColumns:"40px 1fr 1fr 40px",gap:8,padding:"6px 10px",background:i%2===0?"#fff":"#f9fbff",borderBottom:"1px solid #f0f4f8",alignItems:"center"}}>
                      <span style={{fontSize:12,color:"#9ca3af",textAlign:"center"}}>{i+1}</span>
                      <input value={f.grado} onChange={e=>{const c=[...tiposFilas];c[i]={...c[i],grado:e.target.value};setTiposFilas(c);}}
                        style={{padding:"5px 8px",borderRadius:6,border:"1.5px solid #ddd",fontSize:12,width:"100%",boxSizing:"border-box"}}/>
                      <input value={f.tutor} onChange={e=>{const c=[...tiposFilas];c[i]={...c[i],tutor:e.target.value};setTiposFilas(c);}}
                        style={{padding:"5px 8px",borderRadius:6,border:"1.5px solid #ddd",fontSize:12,width:"100%",boxSizing:"border-box"}}/>
                      <button onClick={()=>setTiposFilas(tiposFilas.filter((_,idx)=>idx!==i))}
                        style={{background:"#f8d7da",border:"none",borderRadius:6,color:"#721c24",fontWeight:700,cursor:"pointer",fontSize:14,padding:"4px 8px"}}>✕</button>
                    </div>
                  ))}
                </div>
              </div>
              <div style={{display:"flex",gap:10}}>
                <button onClick={()=>setTiposFilas([...tiposFilas,{grado:"",tutor:""}])}
                  style={{padding:"8px 16px",borderRadius:8,background:"#e9ecef",color:"#374151",fontWeight:600,fontSize:13,border:"1.5px solid #d1d5db",cursor:"pointer"}}>➕ Agregar fila</button>
                <button onClick={guardarTipos}
                  style={{padding:"8px 20px",borderRadius:8,background:"#1565c0",color:"#fff",fontWeight:700,fontSize:13,border:"none",cursor:"pointer"}}>💾 Guardar cambios</button>
              </div>
            </div>
          )}

          {/* ── IMPORTAR SIMAT ── */}
          {subTab==="simat"&&(
            <div style={{background:"#e8f4fd",border:"2px dashed #1565c0",borderRadius:12,padding:28,textAlign:"center"}}>
              <div style={{fontSize:40,marginBottom:8}}>📊</div>
              <div style={{fontWeight:700,fontSize:15,color:"#1e3a5f",marginBottom:6}}>Cargar nuevo SIMAT</div>
              <div style={{fontSize:12,color:"#6b7280",marginBottom:16}}>Archivo .xlsx con hojas <b>SIMAT</b> y <b>Tipos</b></div>
              <label style={{display:"inline-block",padding:"10px 24px",background:"#1565c0",color:"#fff",borderRadius:8,cursor:"pointer",fontWeight:700,fontSize:13}}>
                📂 Seleccionar archivo .xlsx
                <input type="file" accept=".xlsx,.xls" onChange={handleSIMAT} style={{display:"none"}}/>
              </label>
              {simatMsg&&<div style={{marginTop:14,padding:"10px 16px",borderRadius:8,fontSize:13,fontWeight:600,
                background:simatMsg.startsWith("✅")?"#d4edda":simatMsg.startsWith("❌")?"#f8d7da":"#fff3cd",
                color:simatMsg.startsWith("✅")?"#1e7e34":simatMsg.startsWith("❌")?"#721c24":"#856404"}}>{simatMsg}</div>}
            </div>
          )}

          {/* ── BORRAR BD ── */}
          {subTab==="borrar"&&(
            <div style={{background:"#fff5f5",border:"2px solid #dc354530",borderRadius:12,padding:28,textAlign:"center"}}>
              <div style={{fontSize:48,marginBottom:8}}>⚠️</div>
              <div style={{fontWeight:700,fontSize:16,color:"#721c24",marginBottom:8}}>Borrar Base de Datos</div>
              <div style={{fontSize:13,color:"#6b7280",marginBottom:20,lineHeight:1.6}}>
                Elimina todos los estados, asistencia, notas y entregas.<br/>
                Los datos del SIMAT se mantienen.<br/><strong>Esta acción no se puede deshacer.</strong>
              </div>
              {!confirmarBorrar?(
                <button onClick={()=>setConfirmarBorrar(true)} style={{padding:"10px 28px",borderRadius:8,background:"#dc3545",color:"#fff",fontWeight:700,fontSize:14,border:"none",cursor:"pointer"}}>🗑️ Borrar todos los datos</button>
              ):(
                <div>
                  <div style={{fontSize:13,fontWeight:600,color:"#721c24",marginBottom:12}}>¿Estás seguro? Esta acción es irreversible.</div>
                  <div style={{display:"flex",gap:12,justifyContent:"center"}}>
                    <button onClick={borrarBD} style={{padding:"10px 24px",borderRadius:8,background:"#dc3545",color:"#fff",fontWeight:700,fontSize:14,border:"none",cursor:"pointer"}}>✅ Sí, borrar todo</button>
                    <button onClick={()=>setConfirmarBorrar(false)} style={{padding:"10px 24px",borderRadius:8,background:"#e9ecef",color:"#374151",fontWeight:700,fontSize:14,border:"none",cursor:"pointer"}}>❌ Cancelar</button>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ══ REPORTES ═══════════════════════════════════════════════════════════
function ReportesTab({datosEscuela,appState}){
  const [filtroGrado,setFG]=useState("TODOS");
  const [filtroEstado,setFE]=useState("TODOS");
  const [filtroSimat,setFS]=useState("TODOS");
  const [filtroRuta,setFR]=useState("TODOS");
  const [vista,setVista]=useState("dashboard");

  const todos=GRADOS_ORDEN.filter(g=>datosEscuela[g]).flatMap(grado=>{
    const ests=datosEscuela[grado].estudiantes;
    const st=appState?.[grado]?.comisiones||{};
    return ests.map((e,i)=>({...e,grado,tutor:datosEscuela[grado].tutor,estadoComision:st[i]?.estado||e.estado||"MATRICULADO"}));
  });
  const filtrados=todos.filter(e=>{
    if(filtroGrado!=="TODOS"&&e.grado!==filtroGrado)return false;
    if(filtroEstado!=="TODOS"&&e.estadoComision!==filtroEstado)return false;
    if(filtroSimat!=="TODOS"&&(e.simat||"NO REGISTRADO")!==filtroSimat)return false;
    if(filtroRuta==="CON RUTA"&&!e.ruta)return false;
    if(filtroRuta==="SIN RUTA"&&e.ruta)return false;
    return true;
  });
  const total=todos.length;
  const pct=(n,d)=>d===0?"0%":(n/d*100).toFixed(1)+"%";
  const porEstado={};ESTADOS.forEach(e=>{porEstado[e.key]=todos.filter(x=>x.estadoComision===e.key).length;});
  const porGenero={M:todos.filter(e=>e.genero!=="F").length,F:todos.filter(e=>e.genero==="F").length};
  const conRuta=todos.filter(e=>e.ruta).length;
  const porSimat={};SIMAT_ESTADOS.forEach(s=>{porSimat[s.key]=todos.filter(e=>(e.simat||"NO REGISTRADO")===s.key).length;});
  const rutasUnicas=[...new Set(todos.filter(e=>e.ruta).map(e=>e.ruta))].sort();

  function BarChart({data}){
    const max=Math.max(...data.map(d=>d.val),1);
    return(<div style={{display:"flex",flexDirection:"column",gap:5}}>
      {data.map((d,i)=>(
        <div key={i} style={{display:"flex",alignItems:"center",gap:8}}>
          <div style={{fontSize:10,color:"#374151",minWidth:145,textAlign:"right"}}>{d.label}</div>
          <div style={{flex:1,background:"#f0f4f8",borderRadius:4,height:20,position:"relative"}}>
            <div style={{width:(d.val/max*100)+"%",background:d.color,height:"100%",borderRadius:4,transition:"width .4s",minWidth:d.val>0?6:0}}/>
            <span style={{position:"absolute",left:6,top:"50%",transform:"translateY(-50%)",fontSize:10,fontWeight:700,color:"#fff",mixBlendMode:"difference"}}>
              {d.val} ({pct(d.val,total)})
            </span>
          </div>
        </div>
      ))}
    </div>);
  }

  const KPI=({val,label,pctVal,grad})=>(
    <div style={{background:grad,borderRadius:12,padding:"14px 12px",textAlign:"center",color:"#fff"}}>
      <div style={{fontSize:30,fontWeight:800}}>{val}</div>
      <div style={{fontSize:10,opacity:.85,marginTop:2}}>{label}</div>
      {pctVal&&<div style={{fontSize:11,fontWeight:700,marginTop:2}}>{pct(pctVal,total)}</div>}
    </div>
  );

  return(
    <div>
      <div style={{display:"flex",gap:8,marginBottom:18,flexWrap:"wrap"}}>
        {[["dashboard","📊 Dashboard"],["tabla","📋 Tabla con filtros"],["ruta","🚌 Por Rutas"]].map(([k,l])=>(
          <button key={k} onClick={()=>setVista(k)}
            style={{padding:"7px 16px",borderRadius:8,border:"none",cursor:"pointer",fontSize:13,fontWeight:vista===k?700:500,
              background:vista===k?"#1565c0":"#e8edf5",color:vista===k?"#fff":"#374151"}}>{l}</button>
        ))}
      </div>

      {vista==="dashboard"&&(
        <div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))",gap:12,marginBottom:20}}>
            <KPI val={total} label="TOTAL ESTUDIANTES" grad="linear-gradient(135deg,#1565c0,#0d47a1)"/>
            <KPI val={porEstado["MATRICULADO"]||0} label="MATRICULADOS" pctVal={porEstado["MATRICULADO"]||0} grad="linear-gradient(135deg,#1e7e34,#155724)"/>
            <KPI val={porEstado["PROMOVIDO"]||0} label="PROMOVIDOS" pctVal={porEstado["PROMOVIDO"]||0} grad="linear-gradient(135deg,#004085,#002752)"/>
            <KPI val={porEstado["RETIRADO"]||0} label="RETIRADOS" pctVal={porEstado["RETIRADO"]||0} grad="linear-gradient(135deg,#721c24,#4e1217)"/>
            <KPI val={porEstado["REPROBADO"]||0} label="REPROBADOS" pctVal={porEstado["REPROBADO"]||0} grad="linear-gradient(135deg,#856404,#533f03)"/>
            <KPI val={(porEstado["COMPROMISO CONVIVENCIAL"]||0)+(porEstado["COMPROMISO ACADEMICO"]||0)} label="EN COMPROMISO" pctVal={(porEstado["COMPROMISO CONVIVENCIAL"]||0)+(porEstado["COMPROMISO ACADEMICO"]||0)} grad="linear-gradient(135deg,#5a1e6b,#3b1247)"/>
            <KPI val={porEstado["CONTINUIDAD"]||0} label="CONTINUIDAD" pctVal={porEstado["CONTINUIDAD"]||0} grad="linear-gradient(135deg,#495057,#212529)"/>
            <KPI val={conRuta} label="CON RUTA" pctVal={conRuta} grad="linear-gradient(135deg,#c01565,#7a0d41)"/>
            <KPI val={porGenero.M} label="HOMBRES" pctVal={porGenero.M} grad="linear-gradient(135deg,#0d6efd,#0a58ca)"/>
            <KPI val={porGenero.F} label="MUJERES" pctVal={porGenero.F} grad="linear-gradient(135deg,#d63384,#a71e5d)"/>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:16}}>
            <div style={{background:"#fff",borderRadius:12,padding:16,boxShadow:"0 1px 6px rgba(0,0,0,.08)"}}>
              <div style={{fontWeight:700,fontSize:13,color:"#1e3a5f",marginBottom:12}}>📊 Por Estado de Comisión</div>
              <BarChart data={ESTADOS.map(e=>({label:e.label,val:porEstado[e.key]||0,color:e.color}))}/>
            </div>
            <div style={{background:"#fff",borderRadius:12,padding:16,boxShadow:"0 1px 6px rgba(0,0,0,.08)"}}>
              <div style={{fontWeight:700,fontSize:13,color:"#1e3a5f",marginBottom:12}}>📋 Estado SIMAT</div>
              <BarChart data={SIMAT_ESTADOS.map(s=>({label:s.label,val:porSimat[s.key]||0,color:s.color}))}/>
            </div>
          </div>
          <div style={{background:"#fff",borderRadius:12,padding:16,boxShadow:"0 1px 6px rgba(0,0,0,.08)",marginBottom:16}}>
            <div style={{fontWeight:700,fontSize:13,color:"#1e3a5f",marginBottom:12}}>🏫 Estudiantes por Grado</div>
            <BarChart data={GRADOS_ORDEN.filter(g=>datosEscuela[g]).map(g=>({label:g,val:datosEscuela[g].estudiantes.length,color:"#1565c0"}))}/>
          </div>
          {(porEstado["RETIRADO"]||0)>0&&(
            <div style={{background:"#fff",borderRadius:12,padding:16,boxShadow:"0 1px 6px rgba(0,0,0,.08)"}}>
              <div style={{fontWeight:700,fontSize:13,color:"#721c24",marginBottom:10}}>🚨 Retirados ({porEstado["RETIRADO"]})</div>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                <thead><tr style={{background:"#f8d7da"}}>
                  <th style={TH}>#</th><th style={{...TH,textAlign:"left"}}>Nombre</th><th style={TH}>Grado</th><th style={TH}>Gén.</th>
                </tr></thead>
                <tbody>{todos.filter(e=>e.estadoComision==="RETIRADO").map((e,i)=>(
                  <tr key={i} style={{borderBottom:"1px solid #f0f4f8",background:i%2===0?"#fff":"#fff5f5"}}>
                    <td style={{...TD,textAlign:"center",color:"#9ca3af"}}>{i+1}</td>
                    <td style={{...TD,color:"#721c24",textDecoration:"line-through"}}>{e.nombre}</td>
                    <td style={{...TD,textAlign:"center"}}>{e.grado}</td>
                    <td style={{...TD,textAlign:"center"}}>{e.genero}</td>
                  </tr>
                ))}</tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {vista==="tabla"&&(
        <div>
          <div style={{background:"#fff",borderRadius:12,padding:14,marginBottom:14,boxShadow:"0 1px 6px rgba(0,0,0,.08)",display:"flex",gap:12,flexWrap:"wrap",alignItems:"flex-end"}}>
            {[
              {label:"Grado",val:filtroGrado,set:setFG,opts:[["TODOS","Todos"],,...GRADOS_ORDEN.filter(g=>datosEscuela[g]).map(g=>[g,g])]},
              {label:"Estado Comisión",val:filtroEstado,set:setFE,opts:[["TODOS","Todos"],...ESTADOS.map(e=>[e.key,e.label])]},
              {label:"Estado SIMAT",val:filtroSimat,set:setFS,opts:[["TODOS","Todos"],...SIMAT_ESTADOS.map(s=>[s.key,s.label])]},
              {label:"Ruta",val:filtroRuta,set:setFR,opts:[["TODOS","Todos"],["CON RUTA","Con ruta"],["SIN RUTA","Sin ruta"]]},
            ].map(({label,val,set,opts})=>(
              <div key={label}>
                <label style={{fontSize:11,fontWeight:600,color:"#374151",display:"block",marginBottom:3}}>{label}</label>
                <select value={val} onChange={e=>set(e.target.value)} style={{padding:"6px 10px",borderRadius:7,border:"1.5px solid #ddd",fontSize:12}}>
                  {opts.map(([v,l])=><option key={v} value={v}>{l}</option>)}
                </select>
              </div>
            ))}
            <div style={{marginLeft:"auto",fontSize:13,fontWeight:600,color:"#1565c0"}}>{filtrados.length} de {total}</div>
          </div>
          <div style={{background:"#fff",borderRadius:12,overflow:"auto",boxShadow:"0 1px 6px rgba(0,0,0,.08)"}}>
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
              <thead><tr style={{background:"#1565c0",color:"#fff"}}>
                <th style={{...TH,color:"#fff"}}>#</th>
                <th style={{...TH,textAlign:"left",color:"#fff",minWidth:180}}>Apellidos y Nombres</th>
                <th style={{...TH,color:"#fff"}}>Grado</th>
                <th style={{...TH,color:"#fff"}}>Gén.</th>
                <th style={{...TH,color:"#fff",minWidth:130}}>Estado Comisión</th>
                <th style={{...TH,color:"#fff"}}>SIMAT</th>
                <th style={{...TH,color:"#fff"}}>Documento</th>
                <th style={{...TH,color:"#fff"}}>F.Nac.</th>
                <th style={{...TH,color:"#fff"}}>Ruta</th>
                <th style={{...TH,color:"#fff"}}>Transportador</th>
              </tr></thead>
              <tbody>{filtrados.map((e,i)=>{
                const info=eInfo(e.estadoComision);
                const si=SIMAT_ESTADOS.find(s=>s.key===(e.simat||"NO REGISTRADO"))||SIMAT_ESTADOS[2];
                return(<tr key={i} style={{background:i%2===0?"#fff":"#f9fbff",borderBottom:"1px solid #e9ecf0"}}>
                  <td style={{...TD,textAlign:"center",color:"#9ca3af"}}>{i+1}</td>
                  <td style={{...TD,fontWeight:500}}>{e.nombre}</td>
                  <td style={{...TD,textAlign:"center",fontSize:11}}>{e.grado}</td>
                  <td style={{...TD,textAlign:"center"}}>{e.genero}</td>
                  <td style={TD}><span style={{background:info.bg,color:info.color,padding:"2px 6px",borderRadius:4,fontSize:10,fontWeight:600}}>{info.label}</span></td>
                  <td style={TD}><span style={{background:si.bg,color:si.color,padding:"2px 6px",borderRadius:4,fontSize:10,fontWeight:600}}>{si.label}</span></td>
                  <td style={{...TD,fontSize:11}}>{e.documento||"–"}</td>
                  <td style={{...TD,textAlign:"center",fontSize:11}}>{e.fechaNac||"–"}</td>
                  <td style={{...TD,fontSize:11}}>{e.ruta||"–"}</td>
                  <td style={{...TD,fontSize:11}}>{e.transportador||"–"}</td>
                </tr>);
              })}</tbody>
            </table>
          </div>
        </div>
      )}

      {vista==="ruta"&&(
        <div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(150px,1fr))",gap:12,marginBottom:16}}>
            <KPI val={conRuta} label="CON RUTA" pctVal={conRuta} grad="linear-gradient(135deg,#c01565,#7a0d41)"/>
            <KPI val={total-conRuta} label="SIN RUTA" pctVal={total-conRuta} grad="linear-gradient(135deg,#495057,#212529)"/>
            <KPI val={rutasUnicas.length} label="RUTAS DISTINTAS" grad="linear-gradient(135deg,#1565c0,#0d47a1)"/>
          </div>
          {rutasUnicas.map(ruta=>{
            const ests=todos.filter(e=>e.ruta===ruta);
            const trans=[...new Set(ests.map(e=>e.transportador).filter(Boolean))];
            return(<div key={ruta} style={{background:"#fff",borderRadius:12,marginBottom:12,overflow:"hidden",boxShadow:"0 1px 6px rgba(0,0,0,.08)"}}>
              <div style={{background:"#c01565",color:"#fff",padding:"9px 16px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontWeight:700,fontSize:13}}>🚌 {ruta}</span>
                <span style={{fontSize:12}}>{ests.length} estudiantes · {trans.join(", ")||"Sin transportador"}</span>
              </div>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                <thead><tr style={{background:"#f9f0f5"}}>
                  <th style={TH}>#</th><th style={{...TH,textAlign:"left"}}>Nombre</th><th style={TH}>Grado</th><th style={TH}>Gén.</th><th style={TH}>Transportador</th>
                </tr></thead>
                <tbody>{ests.map((e,i)=>(
                  <tr key={i} style={{borderBottom:"1px solid #f0f4f8",background:i%2===0?"#fff":"#fdf8fb"}}>
                    <td style={{...TD,textAlign:"center",color:"#9ca3af"}}>{i+1}</td>
                    <td style={{...TD,fontWeight:500}}>{e.nombre}</td>
                    <td style={{...TD,textAlign:"center",fontSize:11}}>{e.grado}</td>
                    <td style={{...TD,textAlign:"center"}}>{e.genero}</td>
                    <td style={{...TD,fontSize:11}}>{e.transportador||"–"}</td>
                  </tr>
                ))}</tbody>
              </table>
            </div>);
          })}
          {rutasUnicas.length===0&&<div style={{background:"#fff",borderRadius:12,padding:32,textAlign:"center",color:"#9ca3af",fontSize:13}}>No hay estudiantes con ruta asignada.</div>}
        </div>
      )}
    </div>
  );
}

// ══ APP PRINCIPAL ══════════════════════════════════════════════════════
const TABS_DEF=[
  {key:"comisiones", label:"📋 Comisiones"},
  {key:"asistencia", label:"📅 Asistencia y Notas",  adminOnly:true, coordOk:true},
  {key:"entregas",   label:"📦 Entrega Informes",     adminOnly:true, coordOk:true},
  {key:"consolidado",label:"📊 Consolidado Final"},
  {key:"reportes",   label:"📈 Reportes",             adminOnly:true, coordOk:true},
];

export default function App(){
  const [auth,setAuth]=useState(()=>ls(AK,null));
  const [datos,setDatos]=useState(()=>ls(DK,DATOS_INICIAL));
  const [tab,setTab]=useState("comisiones");
  const [gradoSel,setGradoSel]=useState(()=>{const a=ls(AK,null);return a?.grado||GRADOS_ORDEN.find(g=>ls(DK,DATOS_INICIAL)[g])||"";});
  const [appState,setAppState]=useState(()=>ls(SK,{}));
  const [showAdmin,setShowAdmin]=useState(false);

  useEffect(()=>{ss(SK,appState);},[appState]);

  const update=useCallback((fn)=>{setAppState(prev=>fn(JSON.parse(JSON.stringify(prev))));},[]);

  if(!auth)return <Login onLogin={sess=>{setAuth(sess);if(sess.grado)setGradoSel(sess.grado);else setGradoSel(GRADOS_ORDEN.find(g=>datos[g])||"");}}/>;

  const isAdmin=auth.role==="admin";
  const isCoord=auth.role==="coordinador";
  const grados=GRADOS_ORDEN.filter(g=>datos[g]);
  const gradoData=datos[gradoSel]||{tutor:"",estudiantes:[]};
  const estudiantes=gradoData.estudiantes;

  function getE(i){return appState?.[gradoSel]?.comisiones?.[i]?.estado||estudiantes[i]?.estado||"MATRICULADO";}
  function setE(i,v){update(p=>{if(!p[gradoSel])p[gradoSel]={};if(!p[gradoSel].comisiones)p[gradoSel].comisiones={};if(!p[gradoSel].comisiones[i])p[gradoSel].comisiones[i]={};p[gradoSel].comisiones[i].estado=v;return p;});}
  function getA(i,s,d){return appState?.[gradoSel]?.asistencia?.[i]?.[s]?.[d]||"";}
  function togA(i,s,d){update(p=>{if(!p[gradoSel])p[gradoSel]={};if(!p[gradoSel].asistencia)p[gradoSel].asistencia={};if(!p[gradoSel].asistencia[i])p[gradoSel].asistencia[i]={};if(!p[gradoSel].asistencia[i][s])p[gradoSel].asistencia[i][s]={};const c=p[gradoSel].asistencia[i][s][d]||"";p[gradoSel].asistencia[i][s][d]=c==="P"?"F":c==="F"?"":"P";return p;});}
  function getN(i,per,sab){return appState?.[gradoSel]?.notas?.[i]?.[per]?.[sab]??"";}
  function setN(i,per,sab,v){update(p=>{if(!p[gradoSel])p[gradoSel]={};if(!p[gradoSel].notas)p[gradoSel].notas={};if(!p[gradoSel].notas[i])p[gradoSel].notas[i]={};if(!p[gradoSel].notas[i][per])p[gradoSel].notas[i][per]={};p[gradoSel].notas[i][per][sab]=v;return p;});}
  function getEnt(i){return appState?.[gradoSel]?.entregas?.[i]??false;}
  function togEnt(i){update(p=>{if(!p[gradoSel])p[gradoSel]={};if(!p[gradoSel].entregas)p[gradoSel].entregas={};p[gradoSel].entregas[i]=!p[gradoSel].entregas[i];return p;});}
  function getSimat(i){return appState?.[gradoSel]?.simat?.[i]||estudiantes[i]?.simat||"NO REGISTRADO";}
  function setSimat(i,v){update(p=>{if(!p[gradoSel])p[gradoSel]={};if(!p[gradoSel].simat)p[gradoSel].simat={};p[gradoSel].simat[i]=v;return p;});}
  function calcProm(i,per){const v=SABERES.map(s=>parseFloat(getN(i,per,s))).filter(n=>!isNaN(n));return v.length?(v.reduce((a,b)=>a+b,0)/v.length).toFixed(1):"";}
  function calcPG(i){const v=PERIODOS.flatMap(p=>SABERES.map(s=>parseFloat(getN(i,p,s)))).filter(n=>!isNaN(n));return v.length?(v.reduce((a,b)=>a+b,0)/v.length).toFixed(1):"";}
  function cntA(i){let p=0,f=0;SEMANAS.forEach(s=>DIAS.forEach((_,d)=>{const v=getA(i,s,d.toString());if(v==="P")p++;else if(v==="F")f++;}));return{p,f};}

  const cnt={};ESTADOS.forEach(e=>{cnt[e.key]=0;});estudiantes.forEach((_,i)=>{const e=getE(i);if(cnt[e]!==undefined)cnt[e]++;});

  function handlePrint(){
    const titulos={comisiones:"Acta de Comisión Final",asistencia:"Asistencia y Notas",entregas:"Asistencia Entrega de Informes",consolidado:"Consolidado Final"};
    const ps=`<style>@page{size:landscape;margin:1cm}body{font-family:'Segoe UI',sans-serif;font-size:10px}
    .ph{text-align:center;margin-bottom:12px}.ph h1{font-size:13px;margin:0 0 2px}.ph h2{font-size:11px;margin:0}.ph p{font-size:10px;color:#444}
    table{width:100%;border-collapse:collapse;font-size:9px}th{background:#1565c0!important;color:#fff!important;padding:5px 6px;border:1px solid #ccc;text-align:center}
    td{padding:4px 6px;border:1px solid #ccc}tr:nth-child(even)td{background:#f5f8ff}
    .ret td{background:#fff0f0!important;text-decoration:line-through;color:#c00}
    .pk{background:#d4edda!important;color:#1e7e34;font-weight:700}.fk{background:#f8d7da!important;color:#721c24;font-weight:700}
    .pok{color:#1e7e34;font-weight:700}.pmal{color:#c00;font-weight:700}
    .counters{display:flex;gap:8px;margin-bottom:10px;flex-wrap:wrap}.counter{border:1px solid #ccc;border-radius:6px;padding:4px 10px;text-align:center;min-width:80px}
    .counter .num{font-size:18px;font-weight:700}.counter .lbl{font-size:8px;font-weight:600}</style>`;
    let body="";
    if(tab==="comisiones"){
      const hc=ESTADOS.slice(1).map(e=>`<th style="font-size:8px">${e.label}</th>`).join("");
      const rows=estudiantes.map((est,i)=>{const ec=getE(i),info=eInfo(ec),ret=ec==="RETIRADO";
        return`<tr class="${ret?"ret":""}"><td style="text-align:center">${i+1}</td><td>${est.nombre}</td><td style="text-align:center">${est.genero}</td>
        <td style="text-align:center"><span style="background:${info.bg};color:${info.color};padding:1px 5px;border-radius:3px;font-size:8px">${info.label}</span></td>
        ${ESTADOS.slice(1).map(e=>`<td style="text-align:center">${ec===e.key?"✓":"–"}</td>`).join("")}</tr>`;
      }).join("");
      const cc=ESTADOS.map(e=>`<div class="counter"><div class="num" style="color:${e.color}">${cnt[e.key]}</div><div class="lbl" style="color:${e.color}">${e.label.toUpperCase()}</div></div>`).join("");
      body=`<div class="counters">${cc}</div><table><thead><tr><th>#</th><th style="text-align:left">Apellidos y Nombres</th><th>Gén.</th><th>Estado</th>${hc}</tr></thead><tbody>${rows}</tbody></table>`;
    }
    if(tab==="asistencia"){
      const sc=SEMANAS.flatMap(s=>DIAS_L.map(d=>`<th>${s}<br/>${d[0]}</th>`)).join("");
      const nc=PERIODOS.flatMap(p=>SABERES.map(s=>`<th>${p}<br/>${s.slice(0,5)}</th>`)).join("");
      const pc2=PERIODOS.map(p=>`<th>${p} PM</th>`).join("");
      const rows=estudiantes.map((est,i)=>{
        const {p,f}=cntA(i);
        const ac=SEMANAS.flatMap(s=>DIAS.map((_,d)=>{const v=getA(i,s,d.toString());return`<td class="${v==="P"?"pk":v==="F"?"fk":""}" style="text-align:center">${v||""}</td>`;})).join("");
        const nc2=PERIODOS.flatMap(per=>SABERES.map(sab=>`<td style="text-align:center">${getN(i,per,sab)}</td>`)).join("");
        const pm=PERIODOS.map(per=>{const pv=calcProm(i,per);return`<td class="${pv&&parseFloat(pv)>=3?"pok":"pmal"}" style="text-align:center">${pv}</td>`;}).join("");
        const pg=calcPG(i);
        return`<tr><td style="text-align:center">${i+1}</td><td>${est.nombre}</td>${ac}<td style="text-align:center;color:#1e7e34;font-weight:700">${p}</td><td style="text-align:center;color:#c00;font-weight:700">${f}</td>${nc2}${pm}<td class="${pg&&parseFloat(pg)>=3?"pok":"pmal"}" style="text-align:center">${pg}</td></tr>`;
      }).join("");
      body=`<table><thead><tr><th>#</th><th style="text-align:left;min-width:130px">Apellidos y Nombres</th>${sc}<th>P</th><th>F</th>${nc}${pc2}<th>PM</th></tr></thead><tbody>${rows}</tbody></table>`;
    }
    if(tab==="entregas"){
      const as=estudiantes.filter((_,i)=>getEnt(i)).length;
      const rows=estudiantes.map((est,i)=>{const a=getEnt(i);return`<tr><td style="text-align:center">${i+1}</td><td>${est.nombre}</td><td style="text-align:center">${est.genero}</td><td style="text-align:center;font-weight:700;color:${a?"#1e7e34":"#c00"}">${a?"✓ Sí":"✗ No"}</td><td></td><td>${est.telefono||""}</td></tr>`;}).join("");
      body=`<div class="counters"><div class="counter"><div class="num" style="color:#1e7e34">${as}</div><div class="lbl" style="color:#1e7e34">ASISTIERON</div></div><div class="counter"><div class="num" style="color:#c00">${estudiantes.length-as}</div><div class="lbl" style="color:#c00">NO ASIST.</div></div><div class="counter"><div class="num" style="color:#004085">${estudiantes.length}</div><div class="lbl" style="color:#004085">TOTAL</div></div></div>
      <table><thead><tr><th>#</th><th style="text-align:left">Apellidos y Nombres</th><th>Gén.</th><th>Asistió</th><th style="min-width:120px">Firma</th><th>Teléfono</th></tr></thead><tbody>${rows}</tbody></table>`;
    }
    if(tab==="consolidado"){
      const filas=GRADOS_ORDEN.filter(g=>datos[g]).map(grado=>{
        const ests=datos[grado].estudiantes,st=appState?.[grado]?.comisiones||{},counts={};
        ESTADOS.forEach(e=>{counts[e.key]={M:0,F:0};});
        ests.forEach((est,i)=>{const ec=st[i]?.estado||est.estado||"MATRICULADO",gen=est.genero==="F"?"F":"M";if(counts[ec])counts[ec][gen]++;});
        return{grado,tutor:datos[grado].tutor,counts,totalM:ests.filter(e=>e.genero!=="F").length,totalF:ests.filter(e=>e.genero==="F").length,total:ests.length};
      });
      const tot={M:0,F:0,total:0},totE={};ESTADOS.forEach(e=>{totE[e.key]={M:0,F:0};});
      filas.forEach(f=>{tot.M+=f.totalM;tot.F+=f.totalF;tot.total+=f.total;ESTADOS.forEach(e=>{totE[e.key].M+=f.counts[e.key].M;totE[e.key].F+=f.counts[e.key].F;});});
      const hc=ESTADOS.map(e=>`<th colspan="2" style="background:${e.color};color:#fff;font-size:8px">${e.label}</th>`).join("");
      const rows=filas.map((f,ri)=>{
        const cols=ESTADOS.map(e=>`<td style="text-align:center;${f.counts[e.key].M>0?`background:${e.bg};color:${e.color};font-weight:700`:""}">${f.counts[e.key].M||"–"}</td><td style="text-align:center;${f.counts[e.key].F>0?`background:${e.bg};color:${e.color};font-weight:700`:""}">${f.counts[e.key].F||"–"}</td>`).join("");
        return`<tr style="${ri%2===0?"":"background:#f5f8ff"}"><td style="font-weight:600">${f.grado}</td><td style="font-size:9px">${f.tutor}</td><td style="text-align:center;color:#1565c0;font-weight:700">${f.totalM}</td><td style="text-align:center;color:#c01565;font-weight:700">${f.totalF}</td><td style="text-align:center;font-weight:700">${f.total}</td>${cols}</tr>`;
      }).join("");
      const tr=ESTADOS.map(e=>`<td style="text-align:center;color:#7dd3fc;font-weight:700">${totE[e.key].M||"–"}</td><td style="text-align:center;color:#f9a8d4;font-weight:700">${totE[e.key].F||"–"}</td>`).join("");
      body=`<table><thead><tr style="background:#1e3a5f;color:#fff"><th colspan="5" style="text-align:left;color:#fff">Grado</th>${hc}</tr><tr style="background:#e8edf5"><th style="text-align:left">Grado</th><th style="text-align:left">Tutor</th><th>♂</th><th>♀</th><th>Total</th>${ESTADOS.map(()=>"<th>♂</th><th>♀</th>").join("")}</tr></thead><tbody>${rows}<tr style="background:#1e3a5f;color:#fff;font-weight:700"><td colspan="2" style="color:#fff">TOTALES</td><td style="text-align:center;color:#7dd3fc">${tot.M}</td><td style="text-align:center;color:#f9a8d4">${tot.F}</td><td style="text-align:center;color:#fff">${tot.total}</td>${tr}</tr></tbody></table>`;
    }
    const titulo=titulos[tab]||"";
    const win=window.open("","_blank");
    win.document.write(`<!DOCTYPE html><html><head><meta charset="utf-8"/>${ps}</head><body><div class="ph"><h1>IED SARID ARTETA DE VÁSQUEZ — INEDISAV</h1><h2>${titulo}</h2><p>${tab==="consolidado"?"Año Escolar 2026":"Grado: <strong>"+gradoSel+"</strong> · Director(a): <strong>"+gradoData.tutor+"</strong> · 2026"}</p></div>${body}</body></html>`);
    win.document.close();win.focus();setTimeout(()=>win.print(),400);
  }

  return(
    <div style={{fontFamily:"'Segoe UI',sans-serif",minHeight:"100vh",background:"#f0f4f8"}}>
      {showAdmin&&<AdminPanel onClose={()=>setShowAdmin(false)} datosEscuela={datos} onDataUpdate={d=>setDatos(d)}/>}

      {/* HEADER */}
      <div style={{background:"linear-gradient(135deg,#0d47a1,#1565c0)",color:"#fff",padding:"12px 24px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div>
          <div style={{fontSize:10,opacity:.75,letterSpacing:2,textTransform:"uppercase"}}>INEDISAV · 2026</div>
          <div style={{fontSize:18,fontWeight:700}}>IED Sarid Arteta de Vásquez</div>
          <div style={{fontSize:11,opacity:.8}}>Sistema de Gestión Académica</div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <div style={{textAlign:"right"}}>
            <div style={{fontSize:12,fontWeight:600}}>{auth.nombre}</div>
            <div style={{fontSize:10,opacity:.75}}>{isAdmin?"Administrador":isCoord?"Coordinación":auth.grado}</div>
          </div>
          {isAdmin&&<button onClick={()=>setShowAdmin(true)} style={{padding:"6px 12px",borderRadius:8,background:"rgba(255,255,255,.2)",border:"1px solid rgba(255,255,255,.4)",color:"#fff",cursor:"pointer",fontSize:12,fontWeight:600}}>⚙️ Admin</button>}
          <button onClick={()=>{ss(AK,null);setAuth(null);}} style={{padding:"6px 12px",borderRadius:8,background:"rgba(255,255,255,.15)",border:"1px solid rgba(255,255,255,.3)",color:"#fff",cursor:"pointer",fontSize:12}}>🚪 Salir</button>
        </div>
      </div>

      {/* SELECTOR GRADO */}
      {tab!=="reportes"&&(
        <div style={{background:"#fff",borderBottom:"2px solid #e3e8f0",padding:"10px 24px",display:"flex",alignItems:"center",gap:16,flexWrap:"wrap"}}>
          <label style={{fontWeight:600,fontSize:13,color:"#374151"}}>📚 Grado:</label>
          {(isAdmin||isCoord)?(
            <select value={gradoSel} onChange={e=>setGradoSel(e.target.value)}
              style={{padding:"6px 14px",borderRadius:8,border:"1.5px solid #bdc3cf",fontSize:14,fontWeight:600,color:"#1e3a5f",background:"#f8faff",cursor:"pointer"}}>
              {grados.map(g=><option key={g} value={g}>{g}</option>)}
            </select>
          ):(
            <span style={{padding:"6px 14px",borderRadius:8,background:"#f0f4f8",fontWeight:700,color:"#1e3a5f",fontSize:14}}>{gradoSel}</span>
          )}
          <div style={{fontSize:13,color:"#6b7280"}}>👤 <strong>{gradoData.tutor||"Sin tutor"}</strong> · {estudiantes.length} estudiantes</div>
        </div>
      )}

      {/* TABS */}
      <div style={{background:"#fff",borderBottom:"2px solid #e3e8f0",padding:"0 24px",display:"flex",gap:4,alignItems:"center",overflowX:"auto"}}>
        {TABS_DEF.filter(t=>!t.adminOnly||isAdmin||(isCoord&&t.coordOk)).map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key)}
            style={{padding:"12px 16px",border:"none",background:"none",cursor:"pointer",fontWeight:tab===t.key?700:400,fontSize:13,whiteSpace:"nowrap",
              color:tab===t.key?"#1565c0":"#6b7280",borderBottom:tab===t.key?"3px solid #1565c0":"3px solid transparent",marginBottom:-2,transition:"all .15s"}}>
            {t.label}
          </button>
        ))}
        {tab!=="reportes"&&(
          <div style={{marginLeft:"auto"}}>
            <button onClick={handlePrint} style={{padding:"7px 18px",borderRadius:8,border:"1.5px solid #1565c0",background:"#1565c0",color:"#fff",fontWeight:700,fontSize:13,cursor:"pointer"}}>🖨️ Imprimir</button>
          </div>
        )}
      </div>

      <div style={{padding:"20px 24px",maxWidth:1400,margin:"0 auto"}}>

        {/* COMISIONES */}
        {tab==="comisiones"&&(
          <div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:10,marginBottom:20}}>
              {ESTADOS.map(e=>(
                <div key={e.key} style={{background:e.bg,border:`2px solid ${e.color}20`,borderRadius:10,padding:"12px 14px",textAlign:"center"}}>
                  <div style={{fontSize:26,fontWeight:700,color:e.color}}>{cnt[e.key]}</div>
                  <div style={{fontSize:10,fontWeight:600,color:e.color}}>{e.label.toUpperCase()}</div>
                </div>
              ))}
            </div>
            <div style={{background:"#fff",borderRadius:12,overflow:"hidden",boxShadow:"0 1px 6px rgba(0,0,0,.08)"}}>
              <div style={{background:"#1565c0",color:"#fff",padding:"10px 16px",fontSize:13,fontWeight:600}}>
                ACTA DE COMISIÓN FINAL · {gradoSel} · Tutor: {gradoData.tutor}
              </div>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
                <thead><tr style={{background:"#e8edf5"}}>
                  <th style={TH}>#</th>
                  <th style={{...TH,textAlign:"left"}}>Apellidos y Nombres</th>
                  <th style={TH}>Gén.</th>
                  <th style={{...TH,minWidth:180}}>Estado Comisión</th>
                  {ESTADOS.slice(1).map(e=><th key={e.key} style={{...TH,fontSize:10,maxWidth:60,lineHeight:1.2}}>{e.label}</th>)}
                  {isAdmin&&<th style={{...TH,minWidth:130,fontSize:10,background:"#1e3a5f",color:"#fff"}}>Estado SIMAT</th>}
                </tr></thead>
                <tbody>
                  {estudiantes.map((est,i)=>{
                    const ec=getE(i),info=eInfo(ec),ret=ec==="RETIRADO";
                    return(<tr key={i} style={{background:ret?"#fff5f5":i%2===0?"#fff":"#f9fbff",borderBottom:"1px solid #e9ecf0"}}>
                      <td style={{...TD,textAlign:"center",color:"#9ca3af"}}>{i+1}</td>
                      <td style={{...TD,fontWeight:ret?400:500,color:ret?"#dc3545":"#1e293b",textDecoration:ret?"line-through":"none"}}>{est.nombre}</td>
                      <td style={{...TD,textAlign:"center",color:"#6b7280"}}>{est.genero}</td>
                      <td style={TD}>
                        <select value={ec} onChange={e=>setE(i,e.target.value)}
                          disabled={isCoord||(!isAdmin&&ec==="RETIRADO")}
                          style={{width:"100%",padding:"5px 8px",borderRadius:6,fontSize:12,fontWeight:600,border:`1.5px solid ${info.color}40`,background:info.bg,color:info.color,cursor:isCoord?"not-allowed":"pointer"}}>
                          {ESTADOS.filter(e=>isAdmin||e.key!=="RETIRADO"||ec==="RETIRADO").map(e=><option key={e.key} value={e.key}>{e.label}</option>)}
                        </select>
                      </td>
                      {ESTADOS.slice(1).map(e=>(
                        <td key={e.key} style={{...TD,textAlign:"center"}}>
                          {ec===e.key?<span style={{fontSize:16}}>✓</span>:<span style={{color:"#d1d5db"}}>–</span>}
                        </td>
                      ))}
                      {isAdmin&&(()=>{const sv=getSimat(i),si=SIMAT_ESTADOS.find(s=>s.key===sv)||SIMAT_ESTADOS[2];return(
                        <td style={TD}>
                          <select value={sv} onChange={e=>setSimat(i,e.target.value)}
                            style={{width:"100%",padding:"5px 8px",borderRadius:6,fontSize:11,fontWeight:600,border:`1.5px solid ${si.color}40`,background:si.bg,color:si.color,cursor:"pointer"}}>
                            {SIMAT_ESTADOS.map(s=><option key={s.key} value={s.key}>{s.label}</option>)}
                          </select>
                        </td>
                      );})()}
                    </tr>);
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* ASISTENCIA Y NOTAS */}
        {tab==="asistencia"&&(isAdmin||isCoord)&&(
          <div style={{overflowX:"auto"}}>
            <div style={{background:"#fff",borderRadius:12,overflow:"hidden",boxShadow:"0 1px 6px rgba(0,0,0,.08)",minWidth:900}}>
              <div style={{background:"#1565c0",color:"#fff",padding:"10px 16px",fontSize:13,fontWeight:600}}>
                ASISTENCIA Y NOTAS · {gradoSel} · Director(a): {gradoData.tutor}
              </div>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
                <thead><tr style={{background:"#e8edf5"}}>
                  <th style={{...TH,fontSize:10}}>#</th>
                  <th style={{...TH,textAlign:"left",minWidth:160,fontSize:10}}>Apellidos y Nombres</th>
                  {SEMANAS.map(s=>DIAS.map((_,di)=>(
                    <th key={s+di} style={{...TH,fontSize:9,maxWidth:28,padding:"4px 2px"}}>{s}-{DIAS_L[di][0]}</th>
                  )))}
                  <th style={{...TH,fontSize:10}}>P</th><th style={{...TH,fontSize:10}}>F</th>
                  {PERIODOS.map(p=>SABERES.map(s=>(
                    <th key={p+s} style={{...TH,fontSize:9,maxWidth:36,lineHeight:1.2}}>{p}<br/>{s.slice(0,5)}</th>
                  )))}
                  {PERIODOS.map(p=><th key={"pm"+p} style={{...TH,fontSize:9}}>{p}<br/>PM</th>)}
                  <th style={{...TH,fontSize:9}}>PM<br/>Gral</th>
                </tr></thead>
                <tbody>
                  {estudiantes.map((est,i)=>{
                    const {p,f}=cntA(i);
                    return(<tr key={i} style={{background:i%2===0?"#fff":"#f9fbff",borderBottom:"1px solid #e9ecf0"}}>
                      <td style={{...TD,textAlign:"center",color:"#9ca3af"}}>{i+1}</td>
                      <td style={{...TD,fontWeight:500}}>{est.nombre}</td>
                      {SEMANAS.map(s=>DIAS.map((_,di)=>{
                        const v=getA(i,s,di.toString());
                        return(<td key={s+di} style={{...TD,textAlign:"center",padding:"2px 1px"}}>
                          <button onClick={()=>isAdmin&&togA(i,s,di.toString())} disabled={!isAdmin}
                            style={{width:24,height:22,border:"1px solid #ddd",borderRadius:4,fontSize:10,fontWeight:700,cursor:isAdmin?"pointer":"default",
                              background:v==="P"?"#d4edda":v==="F"?"#f8d7da":"#fff",color:v==="P"?"#1e7e34":v==="F"?"#721c24":"#9ca3af"}}>
                            {v||"·"}
                          </button>
                        </td>);
                      }))}
                      <td style={{...TD,textAlign:"center",fontWeight:700,color:"#1e7e34"}}>{p}</td>
                      <td style={{...TD,textAlign:"center",fontWeight:700,color:"#dc3545"}}>{f}</td>
                      {PERIODOS.map(per=>SABERES.map((sab,si)=>(
                        <td key={per+si} style={{...TD,padding:"2px 1px"}}>
                          <input type="number" min="1" max="5" step="0.1" value={getN(i,per,sab)} onChange={e=>isAdmin&&setN(i,per,sab,e.target.value)} readOnly={!isAdmin}
                            style={{width:36,padding:"2px 3px",border:"1px solid #ddd",borderRadius:4,fontSize:11,textAlign:"center",background:isAdmin?"#fff":"#f9fbff"}}/>
                        </td>
                      )))}
                      {PERIODOS.map(per=>{const pm=calcProm(i,per);return(
                        <td key={"pm"+per} style={{...TD,textAlign:"center",fontWeight:600,color:parseFloat(pm)>=3?"#1e7e34":"#dc3545",background:"#f0f4f8"}}>{pm}</td>
                      );})}
                      <td style={{...TD,textAlign:"center",fontWeight:700,background:"#e8edf5",color:parseFloat(calcPG(i))>=3?"#1e7e34":"#dc3545"}}>{calcPG(i)}</td>
                    </tr>);
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* ENTREGA INFORMES */}
        {tab==="entregas"&&(isAdmin||isCoord)&&(
          <div>
            <div style={{display:"flex",gap:12,marginBottom:16}}>
              {[{label:"Asistieron",val:estudiantes.filter((_,i)=>getEnt(i)).length,color:"#1e7e34",bg:"#d4edda"},
                {label:"No asistieron",val:estudiantes.filter((_,i)=>!getEnt(i)).length,color:"#721c24",bg:"#f8d7da"},
                {label:"Total",val:estudiantes.length,color:"#004085",bg:"#cce5ff"}
              ].map(c=>(
                <div key={c.label} style={{background:c.bg,border:`2px solid ${c.color}30`,borderRadius:10,padding:"10px 18px",textAlign:"center",minWidth:100}}>
                  <div style={{fontSize:24,fontWeight:700,color:c.color}}>{c.val}</div>
                  <div style={{fontSize:11,color:c.color,fontWeight:600}}>{c.label}</div>
                </div>
              ))}
            </div>
            <div style={{background:"#fff",borderRadius:12,overflow:"hidden",boxShadow:"0 1px 6px rgba(0,0,0,.08)"}}>
              <div style={{background:"#1565c0",color:"#fff",padding:"10px 16px",fontSize:13,fontWeight:600}}>
                REUNIÓN PADRES · {gradoSel} · Director(a): {gradoData.tutor}
              </div>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
                <thead><tr style={{background:"#e8edf5"}}>
                  <th style={TH}>#</th><th style={{...TH,textAlign:"left"}}>Apellidos y Nombres</th>
                  <th style={TH}>Género</th><th style={TH}>Asistió</th><th style={{...TH,textAlign:"left"}}>Teléfono</th>
                </tr></thead>
                <tbody>
                  {estudiantes.map((est,i)=>{
                    const a=getEnt(i);
                    return(<tr key={i} style={{background:a?"#f0fff4":i%2===0?"#fff":"#f9fbff",borderBottom:"1px solid #e9ecf0"}}>
                      <td style={{...TD,textAlign:"center",color:"#9ca3af"}}>{i+1}</td>
                      <td style={{...TD,fontWeight:500}}>{est.nombre}</td>
                      <td style={{...TD,textAlign:"center",color:"#6b7280"}}>{est.genero}</td>
                      <td style={{...TD,textAlign:"center"}}>
                        <button onClick={()=>isAdmin&&togEnt(i)} disabled={!isAdmin}
                          style={{padding:"5px 16px",borderRadius:20,border:"none",cursor:isAdmin?"pointer":"default",fontWeight:700,fontSize:12,background:a?"#d4edda":"#f8d7da",color:a?"#1e7e34":"#721c24"}}>
                          {a?"✓ Sí":"✗ No"}
                        </button>
                      </td>
                      <td style={TD}>{est.telefono?<a href={`tel:${est.telefono}`} style={{color:"#1565c0",textDecoration:"none"}}>📞 {est.telefono}</a>:<span style={{color:"#d1d5db"}}>–</span>}</td>
                    </tr>);
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* CONSOLIDADO */}
        {tab==="consolidado"&&(()=>{
          const filas=GRADOS_ORDEN.filter(g=>datos[g]).map(grado=>{
            const ests=datos[grado].estudiantes,st=appState?.[grado]?.comisiones||{},counts={};
            ESTADOS.forEach(e=>{counts[e.key]={M:0,F:0};});
            ests.forEach((est,i)=>{const ec=st[i]?.estado||est.estado||"MATRICULADO",gen=est.genero==="F"?"F":"M";if(counts[ec])counts[ec][gen]++;});
            return{grado,tutor:datos[grado].tutor,counts,totalM:ests.filter(e=>e.genero!=="F").length,totalF:ests.filter(e=>e.genero==="F").length,total:ests.length};
          });
          const tot={M:0,F:0,total:0},totE={};ESTADOS.forEach(e=>{totE[e.key]={M:0,F:0};});
          filas.forEach(f=>{tot.M+=f.totalM;tot.F+=f.totalF;tot.total+=f.total;ESTADOS.forEach(e=>{totE[e.key].M+=f.counts[e.key].M;totE[e.key].F+=f.counts[e.key].F;});});
          const colW={minWidth:44,textAlign:"center"};
          return(<div>
            <div style={{display:"flex",gap:10,marginBottom:18,flexWrap:"wrap"}}>
              {[{v:tot.total,l:"TOTAL",c:"#1565c0",bg:"#e8f4fd"},{v:tot.M,l:"HOMBRES",c:"#1565c0",bg:"#e8f4fd"},{v:tot.F,l:"MUJERES",c:"#c01565",bg:"#fce8f4"}].map(x=>(
                <div key={x.l} style={{background:x.bg,border:`2px solid ${x.c}20`,borderRadius:10,padding:"12px 20px",textAlign:"center"}}>
                  <div style={{fontSize:30,fontWeight:700,color:x.c}}>{x.v}</div>
                  <div style={{fontSize:11,fontWeight:600,color:x.c}}>{x.l}</div>
                </div>
              ))}
              {ESTADOS.slice(1).map(e=>(
                <div key={e.key} style={{background:e.bg,border:`2px solid ${e.color}20`,borderRadius:10,padding:"12px 16px",textAlign:"center"}}>
                  <div style={{fontSize:22,fontWeight:700,color:e.color}}>{totE[e.key].M+totE[e.key].F}</div>
                  <div style={{fontSize:10,fontWeight:600,color:e.color}}>{e.label.toUpperCase()}</div>
                  <div style={{fontSize:10,color:e.color,opacity:.7}}>♂{totE[e.key].M} · ♀{totE[e.key].F}</div>
                </div>
              ))}
            </div>
            <div style={{background:"#fff",borderRadius:12,overflow:"auto",boxShadow:"0 1px 6px rgba(0,0,0,.08)"}}>
              <div style={{background:"#1565c0",color:"#fff",padding:"10px 16px",fontSize:13,fontWeight:600}}>CONSOLIDADO FINAL · AÑO ESCOLAR 2026</div>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                <thead>
                  <tr style={{background:"#1e3a5f",color:"#fff"}}>
                    <th style={{...TH,textAlign:"left",minWidth:120,color:"#fff"}}>Grado</th>
                    <th style={{...TH,minWidth:160,textAlign:"left",color:"#fff"}}>Tutor(a)</th>
                    <th style={{...TH,...colW,color:"#fff"}}>♂ H</th>
                    <th style={{...TH,...colW,color:"#fff"}}>♀ M</th>
                    <th style={{...TH,...colW,color:"#fff"}}>Total</th>
                    {ESTADOS.map(e=><th key={e.key} colSpan={2} style={{...TH,fontSize:10,background:e.color,color:"#fff",minWidth:80}}>{e.label}</th>)}
                  </tr>
                  <tr style={{background:"#e8edf5"}}>
                    <th style={TH} colSpan={5}></th>
                    {ESTADOS.map(e=>[
                      <th key={e.key+"m"} style={{...TH,fontSize:10,color:e.color}}>♂</th>,
                      <th key={e.key+"f"} style={{...TH,fontSize:10,color:e.color}}>♀</th>
                    ])}
                  </tr>
                </thead>
                <tbody>
                  {filas.map((f,ri)=>(
                    <tr key={f.grado} style={{background:ri%2===0?"#fff":"#f9fbff",borderBottom:"1px solid #e9ecf0"}}>
                      <td style={{...TD,fontWeight:600,color:"#1e3a5f"}}>{f.grado}</td>
                      <td style={{...TD,fontSize:11}}>{f.tutor}</td>
                      <td style={{...TD,textAlign:"center",fontWeight:600,color:"#1565c0"}}>{f.totalM}</td>
                      <td style={{...TD,textAlign:"center",fontWeight:600,color:"#c01565"}}>{f.totalF}</td>
                      <td style={{...TD,textAlign:"center",fontWeight:700}}>{f.total}</td>
                      {ESTADOS.map(e=>[
                        <td key={e.key+"m"} style={{...TD,textAlign:"center",background:f.counts[e.key].M>0?e.bg:"",color:e.color,fontWeight:f.counts[e.key].M>0?700:400}}>{f.counts[e.key].M||"–"}</td>,
                        <td key={e.key+"f"} style={{...TD,textAlign:"center",background:f.counts[e.key].F>0?e.bg:"",color:e.color,fontWeight:f.counts[e.key].F>0?700:400}}>{f.counts[e.key].F||"–"}</td>
                      ])}
                    </tr>
                  ))}
                  <tr style={{background:"#1e3a5f",color:"#fff",fontWeight:700}}>
                    <td style={{...TD,color:"#fff"}} colSpan={2}>TOTALES</td>
                    <td style={{...TD,textAlign:"center",color:"#7dd3fc"}}>{tot.M}</td>
                    <td style={{...TD,textAlign:"center",color:"#f9a8d4"}}>{tot.F}</td>
                    <td style={{...TD,textAlign:"center",color:"#fff",fontSize:14}}>{tot.total}</td>
                    {ESTADOS.map(e=>[
                      <td key={e.key+"m"} style={{...TD,textAlign:"center",color:"#7dd3fc",fontWeight:700}}>{totE[e.key].M||"–"}</td>,
                      <td key={e.key+"f"} style={{...TD,textAlign:"center",color:"#f9a8d4",fontWeight:700}}>{totE[e.key].F||"–"}</td>
                    ])}
                  </tr>
                </tbody>
              </table>
            </div>
          </div>);
        })()}

        {/* REPORTES */}
        {tab==="reportes"&&(isAdmin||isCoord)&&(
          <ReportesTab datosEscuela={datos} appState={appState}/>
        )}

      </div>
    </div>
  );
}

const TH={padding:"8px 10px",fontWeight:700,fontSize:12,color:"#374151",borderRight:"1px solid #e9ecf0",textAlign:"center",whiteSpace:"nowrap"};
const TD={padding:"6px 10px",borderRight:"1px solid #f0f4f8",verticalAlign:"middle"};
